import { afterEach, describe, expect, it, vi } from "vitest";
import { runSessionStart } from "./sessionStart.js";
vi.mock("../buildInfo.js", () => ({
    isDevBuildActive: () => false,
    getDevBuildSummary: () => null,
    formatDevBuildBannerLines: () => [],
}));
vi.mock("../config.js", () => ({
    hasCredentials: vi.fn(() => false),
}));
vi.mock("../updates.js", () => ({
    checkForUpdate: vi.fn(),
    detectLegacyInstall: () => false,
    legacyMigrationMessage: () => "",
}));
vi.mock("../sdkUpdates.js", () => ({
    checkForSdkUpdatesOffline: () => [],
    formatSdkUpdateLine: () => "",
}));
import { hasCredentials } from "../config.js";
const testPlatform = {
    authPath: "test",
    loginHint: "/test:login",
    setupHint: "/test:setup",
    updateHint: "/test:update",
    repo: "Test/test-plugin",
    remotePackageJsonPath: "package.json",
    cliBinary: "test",
    displayName: "Test",
    supportsAutoUpdate: false,
    marketplaceName: "test",
    pluginName: "test",
    marketplacePreRegistered: false,
    pluginUpdateCommands: [],
};
async function captureOutput() {
    let output = "";
    const spy = vi
        .spyOn(process.stdout, "write")
        .mockImplementation((chunk) => {
        output += chunk.toString();
        return true;
    });
    try {
        await runSessionStart("0.0.1", testPlatform);
    }
    finally {
        spy.mockRestore();
    }
    return output;
}
describe("runSessionStart", () => {
    afterEach(() => {
        vi.mocked(hasCredentials).mockReturnValue(false);
    });
    it("tells the user to log in (not run setup) when unauthenticated", async () => {
        const output = await captureOutput();
        const parsed = JSON.parse(output);
        expect(parsed.systemMessage).toContain("[Bitfab] Not authenticated. Run /test:login to log in.");
        expect(parsed.systemMessage).not.toContain("/test:setup");
    });
    it("emits no auth message when authenticated", async () => {
        vi.mocked(hasCredentials).mockReturnValue(true);
        const output = await captureOutput();
        const parsed = output ? JSON.parse(output) : {};
        expect(parsed.systemMessage ?? "").not.toContain("Not authenticated");
    });
    it("always injects the Studio blocking-commands rule as context", async () => {
        vi.mocked(hasCredentials).mockReturnValue(true);
        const output = await captureOutput();
        const parsed = JSON.parse(output);
        const context = parsed.hookSpecificOutput?.additionalContext ?? "";
        expect(parsed.hookSpecificOutput?.hookEventName).toBe("SessionStart");
        expect(context).toContain("BLOCKS until the user");
        expect(context).toContain("startDataset");
        expect(context).toContain("openDatasetExperiments");
        expect(context).toContain("background / long-running process");
    });
});
